@app.route("/metadata")
def metadata():
    settings = OneLogin_Saml2_Settings(settings=saml_settings(), custom_base_path=None)
    metadata = settings.get_sp_metadata()
    errors = settings.validate_metadata(metadata)
    if errors:
        return Response("Metadata validation failed: " + ", ".join(errors), status=500)
    return Response(metadata, mimetype="application/samlmetadata+xml")

@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return render_template_string(LOGIN_FORM, next_url=request.args.get("next", "/"))
    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")
    if not username or not password:
        return Response("Invalid credentials", status=401)
    session["user"] = username
    next_url = request.form.get("next", "/")
    return redirect(next_url)

